import { useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useForm } from "react-hook-form";
import toast from "react-hot-toast";

import { createTrip } from "../../services/tripService";
import styles from "./CreateTrip.module.css";

const CreateTrip = () => {
    const navigate = useNavigate();
    const fileInputRef = useRef(null);
    const [fileName, setFileName] = useState("");

    const {
        register,
        handleSubmit,
        formState: { errors, isSubmitting },
    } = useForm({
        defaultValues: {
            destination: "",
            country: "",
            city: "",
            budget: "",
            startDate: "",
            endDate: "",
            transportation: "Flight",
            description: "",
            travelers: 1,
            isPublic: false,
        },
    });

    const onSubmit = async (data) => {
        const formData = new FormData();
        formData.append("destination", data.destination);
        formData.append("country", data.country);
        formData.append("city", data.city);
        formData.append("budget", data.budget);
        formData.append("startDate", data.startDate);
        formData.append("endDate", data.endDate);
        formData.append("transportation", data.transportation);
        formData.append("description", data.description);
        formData.append("travelers", data.travelers);
        formData.append("isPublic", data.isPublic);

        const file = fileInputRef.current?.files?.[0];
        if (file) {
            formData.append("tripImage", file);
        }

        try {
            const res = await createTrip(formData);
            toast.success("Adventure planned successfully! ✈️");
            navigate(`/trips/${res.trip._id}`);
        } catch (error) {
            toast.error(error.message);
        }
    };

    return (
        <div className={styles.container}>
            <div className={styles.card}>
                <h1>Plan New Adventure</h1>
                <p>Register a new trip log to start tracking your itinerary and expenses.</p>

                <form onSubmit={handleSubmit(onSubmit)} className={styles.formGrid}>
                    <div className={styles.inputGroup}>
                        <label>Destination Title</label>
                        <input
                            type="text"
                            placeholder="e.g. Dream Holiday in Maldives"
                            {...register("destination", { required: "Destination title is required" })}
                        />
                        <span>{errors.destination?.message}</span>
                    </div>

                    <div className={styles.inputGroup}>
                        <label>City</label>
                        <input
                            type="text"
                            placeholder="e.g. Male"
                            {...register("city", { required: "City is required" })}
                        />
                        <span>{errors.city?.message}</span>
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Country</label>
                        <input
                            type="text"
                            placeholder="e.g. Maldives"
                            {...register("country", { required: "Country is required" })}
                        />
                        <span>{errors.country?.message}</span>
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Total Budget ($)</label>
                        <input
                            type="number"
                            placeholder="5000"
                            {...register("budget", {
                                required: "Budget is required",
                                min: { value: 0, message: "Budget must be a positive number" },
                            })}
                        />
                        <span>{errors.budget?.message}</span>
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Start Date</label>
                        <input
                            type="date"
                            {...register("startDate", { required: "Start date is required" })}
                        />
                        <span>{errors.startDate?.message}</span>
                    </div>

                    <div className={styles.inputGroup}>
                        <label>End Date</label>
                        <input
                            type="date"
                            {...register("endDate", { required: "End date is required" })}
                        />
                        <span>{errors.endDate?.message}</span>
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Default Transportation</label>
                        <select {...register("transportation")}>
                            <option value="Flight">✈️ Flight</option>
                            <option value="Train">🚄 Train</option>
                            <option value="Bus">🚌 Bus</option>
                            <option value="Car">🚗 Car</option>
                            <option value="Other">🎒 Other</option>
                        </select>
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Number of Travelers</label>
                        <input
                            type="number"
                            min="1"
                            {...register("travelers", { required: "Travelers count is required" })}
                        />
                        <span>{errors.travelers?.message}</span>
                    </div>

                    <div className={`${styles.inputGroup} ${styles.fullWidth}`}>
                        <label>Trip Cover Image (Optional)</label>
                        <input
                            type="file"
                            accept="image/*"
                            ref={fileInputRef}
                            style={{ display: "none" }}
                            onChange={(e) => setFileName(e.target.files?.[0]?.name || "")}
                        />
                        <div style={{ display: "flex", gap: "10px" }}>
                            <button
                                type="button"
                                onClick={() => fileInputRef.current?.click()}
                                className={styles.saveBtn}
                                style={{ marginTop: "0", background: "var(--border)", color: "var(--text)" }}
                            >
                                Choose File
                            </button>
                            <span style={{ alignSelf: "center", color: "var(--subText)", fontSize: "14px" }}>
                                {fileName || "No file chosen"}
                            </span>
                        </div>
                    </div>

                    <div className={`${styles.inputGroup} ${styles.fullWidth}`}>
                        <label>Trip Description / Notes</label>
                        <textarea
                            placeholder="Describe your trip details, flight tickets, hotel links, or notes..."
                            {...register("description")}
                        />
                    </div>

                    <div className={`${styles.inputGroup} ${styles.fullWidth}`}>
                        <label className={styles.checkboxLabel}>
                            <input type="checkbox" {...register("isPublic")} />
                            Make this trip Public (allows others to view, wishlist, and leave reviews)
                        </label>
                    </div>

                    <div className={styles.fullWidth}>
                        <button type="submit" className={styles.submitBtn} disabled={isSubmitting}>
                            {isSubmitting ? "Planning Adventure..." : "Create Trip Log"}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default CreateTrip;
